class Solution:
    def largest1BorderedSquare(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        m, n = len(grid), len(grid[0])

        # Precompute consecutive 1s horizontally and vertically
        h = [[0] * n for _ in range(m)]  # Consecutive 1s to the right
        v = [[0] * n for _ in range(m)]  # Consecutive 1s below

        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    h[i][j] = 1 + (h[i][j-1] if j > 0 else 0)
                    v[i][j] = 1 + (v[i-1][j] if i > 0 else 0)

        max_side = 0

        # Check all possible squares
        for i in range(m):
            for j in range(n):
                # Maximum possible side from this position
                max_k = min(h[i][j], v[i][j])

                # Check all sizes
                for k in range(max_k, 0, -1):
                    # Check if we can form a k x k square
                    if h[i-k+1][j] >= k and v[i][j-k+1] >= k:
                        max_side = max(max_side, k)
                        break

        return max_side * max_side
